sql:
SELECT model_images.model_id, model_images.image_id
FROM model_images
WHERE model_images.split = 'training';

external_knowledge:
- 'Crown jewel' refers to the most popular image; 
- 'Popularity score' refers to the total number of user approvals; 
- 'Most reliable active model' refers to the model with the highest predicted probability; 
- 'Seal of approval' refers to a user's approval status ('approved').

sql:
SELECT image_id 
FROM user_images 
WHERE status IN ('pending', 'approved');
